class TaskB {

    long n,x,y,c;



	public void solve(int testNumber, InputReader in, OutputWriter out) {
        n = in.readInt();
        x = in.readInt();
        y = in.readInt();
        c = in.readInt();

        int lo = -1;
        int hi = (int)c;

        while(lo+1<hi) {
            int mi = (lo+hi)/2;
            if(P(mi)) hi = mi; else lo = mi;
        }
        out.printLine(hi);
	}

    private boolean P(int t) {
        if(t == -1) return false;

        int ans = 0;
        for(long i = Math.max(1,y-t); i <= Math.min(y+t,n); ++i) {
            long a = Math.abs(y - i);
            ans += D(Math.max(1,x-t+a), Math.min(n,x+t-a));
            if(ans >= c) return true;
        }

        return false;
    }

    private long D(long a, long b) {
        return b - a + 1;
    }
}

class InputReader {

    private InputStream stream;
    private byte[] buf = new byte[1024];
    private int curChar;
    private int numChars;
    private SpaceCharFilter filter;

    public InputReader(InputStream stream) {
        this.stream = stream;
    }

    public int read() {
        if (numChars == -1)
            throw new InputMismatchException();
        if (curChar >= numChars) {
            curChar = 0;
            try {
                numChars = stream.read(buf);
            } catch (IOException e) {
                throw new InputMismatchException();
            }
            if (numChars <= 0)
                return -1;
        }
        return buf[curChar++];
    }

    public int readInt() {
        int c = read();
        while (isSpaceChar(c))
            c = read();
        int sgn = 1;
        if (c == '-') {
            sgn = -1;
            c = read();
        }
        int res = 0;
        do {
            if (c < '0' || c > '9')
                throw new InputMismatchException();
            res *= 10;
            res += c - '0';
            c = read();
        } while (!isSpaceChar(c));
        return res * sgn;
    }

    public boolean isSpaceChar(int c) {
        if (filter != null)
            return filter.isSpaceChar(c);
        return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1;
    }

    public interface SpaceCharFilter {
        public boolean isSpaceChar(int ch);
    }
}

class OutputWriter {
    private final PrintWriter writer;

    public OutputWriter(OutputStream outputStream) {
        writer = new PrintWriter(new BufferedWriter(new OutputStreamWriter(outputStream)));
    }

    public OutputWriter(Writer writer) {
        this.writer = new PrintWriter(writer);
    }

    public void print(Object...objects) {
        for (int i = 0; i < objects.length; i++) {
            if (i != 0)
                writer.print(' ');
            writer.print(objects[i]);
        }
    }

    public void printLine(Object...objects) {
        print(objects);
        writer.println();
    }

    public void close() {
        writer.close();
    }

}

import java.io.PrintWriter;
import java.util.Arrays;
import java.util.Scanner;

public class B {
    static Scanner in; static int next() throws Exception {return in.nextInt();};
//	static StreamTokenizer in; static int next() throws Exception {in.nextToken(); return (int) in.nval;}
//	static BufferedReader in;
    static PrintWriter out;

    public static long count(long k, long x, long y, long n) {
        long sum = 2*k*(k+1)+1;
        if (k >= x-1) {
            sum -= (k-x+1)*(k-x+1);
        }
        if (k >= y-1) {
            sum -= (k-y+1)*(k-y+1);
        }
        if (k + x >= n) {
            sum -= (k+x-n)*(k+x-n);
        }
        if (k + y >= n) {
            sum -= (k+y-n)*(k+y-n);
        }

        if (k > x+y-1) {
            sum += ((k+1-x-y)*(k+1-x-y+1))/2;
        }

        if (k > n-x+y) {
            sum += ((k+x-n-y)*(k+x-n-y+1))/2;
        }

        if (k > n-y+x) {

            sum += ((k+y-n-x)*(k+y-n-x+1))/2;
        }

        if (k > 2*n-x-y+1) {

            sum += ((k-2*n+x+y-1)*(k-2*n+x+y))/2;
        }
        return sum;
    }

    public static void main(String[] args) throws Exception {
        in = new Scanner(System.in);
//		in = new StreamTokenizer(new BufferedReader(new InputStreamReader(System.in)));
//		in = new BufferedReader(new InputStreamReader(System.in));
        out = new PrintWriter(System.out);

        long n = in.nextLong(), x = in.nextLong(), y = in.nextLong(), c = in.nextLong();

        long res = 0;
        while (count(res, x, y, n) < c) res++;
        out.println(res);


        out.println();
        out.close();
    }
}

import java.io.BufferedReader;
import java.io.File;
