            long m = z - n - y + x;
            res += m * (m + 1) / 2;
        }
        if (z > n - x + n - y + 1) {
            long m = z - 2 * n + x + y - 1;
            res += m * (m + 1) / 2;
        }

        return res >= c;
    }

    public void solve() throws Exception {
        n = nextLong();
        x = nextLong();
        y = nextLong();
        c = nextLong();
        long l = 0;
        long r = 2 * n;
        while (r > l) {
            long mid = (r + l) / 2;
            if (check(mid)) {
                r = mid;
            } else {
                l = mid + 1;
            }
        }
        out.println(r);
    }

    public static void main(String[] args) throws Exception {
        new Example().run();
    }
}

