class TaskB {
	public void solve(int testNumber, InputReader in, OutputWriter out) {

        long n = in.nextLong();
        long x = in.nextLong();
        long y = in.nextLong();
        long c = in.nextLong();

        long tl, tr, tt = -1, t;
        tl = 0;
        tr = (long) 4e9;
        while(tl<tr){
            t = (tl+tr)>>1;

            long cc = f(n, t, x, y);
            if(cc>=c){
                tt = t;
                tr = t;
            }else tl = t+1;
        }

        out.writeln(tt);
	}


    public static long f(long n, long t, long x, long y){

        long res = (t*t+t)/2 * 4 + 1;
        long s;

        if(x-t<1){
            s = t-x+1;
            res -= s*s;
        }
        if(y-t<1){
            s = t-y+1;
            res -= s*s;
        }
        if(x+t>n){
            s = x+t-n;
            res -= s*s;
        }
        if(y+t>n){
            s = y+t-n;
            res -= s*s;
        }

        s = t-(Math.abs(x-1)+Math.abs(y-1))-1;
        if(s>0) res+=(s*s+s)/2;

        s = t-(Math.abs(x-1)+Math.abs(n-y))-1;
        if(s>0) res+=(s*s+s)/2;

        s = t-(Math.abs(n-x)+Math.abs(n-y))-1;
        if(s>0) res+=(s*s+s)/2;

        s = t-(Math.abs(n-x)+Math.abs(y-1))-1;
        if(s>0) res+=(s*s+s)/2;


        return res;
    }
