	void solve()
	{
		int n = ni(), x = ni(), y = ni();
		long c = nl();
		int l = x-1, r = n-x;
		int u = y-1, d = n-y;
		long low = -1, high = 2*n+3;
		while(high - low > 1){
			long t = (high + low) / 2;
			long num = diag(t, l, u) + diag(t, r, u) + diag(t, l, d) + diag(t, r, d)
					+ hor(t, l) + hor(t, r) + hor(t, u) + hor(t, d) + 1;
			if(num >= c){
				high = t;
			}else{
				low = t;
			}
		}
		out.println(high);
	}

	long hor(long t, int n)
	{
		return Math.min(t, n);
	}

	long diag(long t, long r, long u)
	{
		if(t > 2+r+u-2){
			return r*u;
		}

		long ret = t*(t-1)/2;
		if(t > r)ret -= (t-r)*(t-r-1)/2;
		if(t > u)ret -= (t-u)*(t-u-1)/2;
		return ret;
	}

