public class B {
	public static void main(String[] args) {
		MScanner sc = new MScanner();
		PrintWriter out = new PrintWriter(System.out);

		long N = sc.nextLong();
		long X = sc.nextLong();
		long Y = sc.nextLong();
		long C = sc.nextLong();

		long low = 0;
		long high = N*2;
		long mid = 0;
		long ans = 0;
		while (low <= high) {
			mid = (low + high) >> 1;
			long painted = F(mid, X-1, Y-1, N);
			if (painted < C) {
				low = mid + 1;
			} else {
				ans = mid;
				high = mid - 1;
			}
		}
		out.println(ans);
		out.close();

	}

	private static long F(long mid, long x, long y, long n) {
		long base = 2 * mid * (mid + 1) + 1;
		base -= excess(mid - x);
		base -= excess(mid - y);
		base -= excess(mid - (n-1-x));
		base -= excess(mid - (n-1-y));
		base += corner(mid - (x + y + 1));
		base += corner(mid - (x + (n - y - 1) + 1));
		base += corner(mid - ((n - x - 1) + y + 1));
		base += corner(mid - (1 + (n - 1 - y) + (n - 1 - x)));
		return base;
	}

	private static long corner(long a) {
		if (a < 0)return 0;
		return (a * a + a) >> 1;
	}

	private static long excess(long thing) {
		if(thing<0)return 0;
		return thing * thing;
	}

	static class MScanner {
		private InputStream stream;
		private byte[] buf = new byte[1024];
		private int curChar;
		private int numChars;

		public MScanner() {
			stream = System.in;
			// stream = new FileInputStream(new File("dec.in"));

		}

