    y = Math.min(y, n - y + 1);
    long t = 0;
    long s = 1;

    while (s < c) {
      t++;

      s += (t * 4) + ((t >= x + y) ? (t - x - y + 1) : 0)
           - ((t >= x) ? (t - x) * 2 + 1 : 0)
           - ((t >= y) ? (t - y) * 2 + 1 : 0)
           + ((t >= x + n - y + 1) ? (t - x - n + y) : 0)
           + ((t >= n - x + 1 + y) ? (t - n + x - y) : 0)
