static long maxXORInRange(long L, long R) 
{ 
    // get xor of limits 
    long LXR = L ^ R; 

    //  loop to get msb position of L^R 
    long msbPos = 0; 
    while (LXR > 0) 
    { 
        msbPos++; 
        LXR >>= 1; 
    } 

    // construct result by adding 1, 
    // msbPos times 
    long maxXOR = 0; 
    long two = 1; 
    while (msbPos-- >0) 
    { 
        maxXOR += two; 
        two <<= 1; 
    } 

    return maxXOR; 
} 


