		int N = array.length;
		int lo=0, hi=N-1;
		if(array[0]>target) return 0;
		if(array[hi]<target) return N;
		int ans =0;
		while(lo<=hi) {
			int mid = lo+(hi-lo)/2;			 
			if (array[mid]<=target) {
				ans = mid;
				lo= mid+1;
			} else {
				hi= mid-1;
			}
		}
		return ans+1;
	}

