	public int kmpMatch(char[] t, char[] p)

	{

		int n = t.length;

		int m = p.length;

		int[] next = new int[m + 1];

		next[0] = -1;

		int j = -1;

		for(int i = 1;i < m;++i)

		{

			while(j >= 0 && p[i] != p[j + 1])

			{

				j = next[j];

			}

			if(p[i] == p[j + 1])

			{

				++j;

			}

			next[i] = j;

		}

		j = -1;

		for(int i = 0;i < n;++i)

		{

			while(j >= 0 && t[i] != p[j + 1])

			{

				j = next[j];

			}

			if(t[i] == p[j + 1])

			{

				++j;

			}

			if(j == m - 1)

			{

				return i - m + 1;

			}

		}

		return -1;

	}



