public class LittleGirlAndMaximumXOR {



    char[] low;

    char[] high;

    long[][][] dp;



    public int getStart(int i, int m) {

        return (m & 1) == 1 ? 0 : low[i];

    }



    public int getEnd(int i, int m) {

        return (m & 2) == 2 ? 1 : high[i];

    }



    public long f(int i, int m1, int m2) {

        if (i == high.length)

            return 0;

        if (dp[i][m1][m2] != -1)

            return dp[i][m1][m2];

        long ret = 0;

        for (int a = getStart(i, m1); a <= getEnd(i, m1); a++)

            for (int b = getStart(i, m2); b <= getEnd(i, m2); b++)

                ret = Math.max(

                        ret,

                        (a ^ b)

                                * (1L << (high.length - i - 1))

                                + f(i + 1, m1 | (a > low[i] ? 1 : 0)

                                        | (a < high[i] ? 2 : 0), m2

                                        | (b > low[i] ? 1 : 0)

                                        | (b < high[i] ? 2 : 0)));

        return dp[i][m1][m2] = ret;

    }



    public void run() {

        Scanner in = new Scanner(System.in);

        long l = in.nextLong();

        long h = in.nextLong();

        String sl = Long.toBinaryString(l);

        String sh = Long.toBinaryString(h);

        while (sl.length() < sh.length())

            sl = "0" + sl;

        low = sl.toCharArray();

        high = sh.toCharArray();

        for (int i = 0; i < low.length; i++) {

            low[i] -= '0';

            high[i] -= '0';

        }

        dp = new long[64][4][4];

        for (int i = 0; i < 64; i++) 

            for(int j = 0;j<4;j++)for(int k=0;k<4;k++)dp[i][j][k]=-1;

        System.out.println(f(0, 0, 0));

    }



    public static void main(String[] args) {

        (new LittleGirlAndMaximumXOR()).run();

    }

}

