class TaskD {

    int binL[], binR[];
    private long memo[][][][][]=new long[65][2][2][2][2];

    private long f( int index, int equalsAToL, int equalsAToR, int equalsBToL, int equalsBToR ) {
        if( index<0 ) return 0;
        if( memo[index][equalsAToL][equalsAToR][equalsBToL][equalsBToR]>=0 )
            return memo[index][equalsAToL][equalsAToR][equalsBToL][equalsBToR]; 

        long ans=0;

        //==============================================================================================================
        // 0 - 0
        if( (equalsAToL==1&&binL[index]==0||equalsAToL==0) && (equalsBToL==1&&binR[index]==0||equalsBToL==0) ) {
            ans=Math.max( ans,
                0 + f( index-1, equalsAToL, 0!=binR[index]||equalsAToR==0?0:1, equalsBToL, 0!=binR[index]||equalsBToR==0?0:1 ) );
        }

        //==============================================================================================================
        // 0 - 1
        if( (equalsAToL==1&&binL[index]==0||equalsAToL==0) && (equalsBToR==1&&binR[index]==1||equalsBToR==0) ) {
            ans=Math.max( ans,
                (1L<<index) + f( index-1, equalsAToL, 0!=binR[index]||equalsAToR==0?0:1, 1!=binL[index]||equalsBToL==0?0:1, equalsBToR ) );
        }

        //==============================================================================================================
        // 1 - 0
        if( (equalsAToR==1&&binR[index]==1||equalsAToR==0) && (equalsBToL==1&&binR[index]==0||equalsBToL==0) ) {
            ans=Math.max( ans,
                (1L<<index) + f( index-1, 1!=binL[index]||equalsAToL==0?0:1, equalsAToR, equalsBToL, 0!=binR[index]||equalsBToR==0?0:1 ) );
        }

        //==============================================================================================================
        // 1 - 1
        if( (equalsAToR==1&&binR[index]==1||equalsAToR==0) && (equalsBToR==1&&binR[index]==1||equalsBToR==0) ) {
            ans=Math.max( ans,
                    0 + f( index-1, 1!=binL[index]||equalsAToL==0?0:1, equalsAToR, 1!=binL[index]||equalsBToL==0?0:1, equalsBToR ) );
        }

        return memo[index][equalsAToL][equalsAToR][equalsBToL][equalsBToR]=ans;
    }

    public void solve(int testNumber, InputReader in, OutputWriter out) {
        long l=in.readLong(), r=in.readLong();
        final int n=63;
        binR=new int[64];
        binL=new int[64];
        for( int i=n; i>=0; i-- ) {
            if( ((1L<<i)&l)!=0 )
                binL[i]=1;
            if( ((1L<<i)&r)!=0 )
                binR[i]=1;
        }

        for( int i=0; i<memo.length; i++ )
            for( int j=0; j<2; j++ )
                for( int k=0; k<2; k++ )
                    for( int p=0; p<2; p++ )
                        for( int q=0; q<2; q++ )
                            memo[i][j][k][p][q]=-1;

        out.printLine( f( n, 1, 1, 1, 1 ) );
    }
}

class InputReader {

    private InputStream stream;
    private byte[] buf = new byte[1024];
    private int curChar;
    private int numChars;
    private SpaceCharFilter filter;

    public InputReader(InputStream stream) {
        this.stream = stream;
    }

    public int read() {
        if (numChars == -1)
            throw new InputMismatchException();
        if (curChar >= numChars) {
            curChar = 0;
            try {
                numChars = stream.read(buf);
            } catch (IOException e) {
                throw new InputMismatchException();
            }
            if (numChars <= 0)
                return -1;
        }
        return buf[curChar++];
    }

    public long readLong() {
        int c = read();
        while (isSpaceChar(c))
            c = read();
        int sgn = 1;
        if (c == '-') {
            sgn = -1;
            c = read();
        }
        long res = 0;
        do {
            if (c < '0' || c > '9')
                throw new InputMismatchException();
            res *= 10;
            res += c - '0';
            c = read();
        } while (!isSpaceChar(c));
        return res * sgn;
    }

    public boolean isSpaceChar(int c) {
        if (filter != null)
            return filter.isSpaceChar(c);
        return isWhitespace(c);
    }

    public static boolean isWhitespace(int c) {
        return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1;
    }

    public interface SpaceCharFilter {
        public boolean isSpaceChar(int ch);
    }
}

