public class Solver {



	public static void main(String[] Args) throws NumberFormatException,

			IOException {

		new Solver().Run();

	}



	PrintWriter pw;

	StringTokenizer Stok;

	BufferedReader br;



	public String nextToken() throws IOException {

		while (Stok == null || !Stok.hasMoreTokens()) {

			Stok = new StringTokenizer(br.readLine());

		}

		return Stok.nextToken();

	}



	public int nextInt() throws NumberFormatException, IOException {

		return Integer.parseInt(nextToken());

	}



	public double nextDouble() throws NumberFormatException, IOException {

		return Double.parseDouble(nextToken());

	}



	public long nextLong() throws NumberFormatException, IOException {

		return Long.parseLong(nextToken());

	}



	final int KOL_BIT=64;

	long l,r;

	int[] left,right, a, b;



	public void Run() throws NumberFormatException, IOException {

		//br = new BufferedReader(new FileReader("input.txt")); pw = new PrintWriter("output.txt");

		br=new BufferedReader(new InputStreamReader(System.in));  pw=new PrintWriter(new OutputStreamWriter(System.out));



		l=nextLong();

		r=nextLong();

		left=new int[KOL_BIT];

		right=new int[KOL_BIT];

		a=new int[KOL_BIT];

		b=new int[KOL_BIT];

		long mask=1;

		for (int i=0; i<KOL_BIT; i++){

			mask=(long)1<<i;

			if ((l & mask)!=0)

				left[i]=1;



			if ((r & mask)!=0)

				right[i]=1;

		}



		boolean isGreater=false;

		boolean lesRight=false;

		boolean moreLeft=false;

		int[] forA, forB; // {min, max}

		int znA=-1, znB=-1;

		for (int i=KOL_BIT-1; i>=0; i--){

			znA=-1;

			znB=-1;

			forA=new int[]{0,1};

			forB=new int[]{0,1};

			if (!lesRight){

				if (right[i]==0)

					forB[1]=0;

			}



			if (!moreLeft){

				if (left[i]==1)

					forA[0]=1;

			}



			if (!isGreater){

				if (forA[0]==1)

					forB[0]=1;

				if (forB[1]==0)

					forA[1]=0;

			}



			if (forA[1]-forA[0]==0)

				znA=forA[0];



			if (forB[1]-forB[0]==0)

				znB=forB[0];



			if (znA==-1){

				if (znB==-1){

					if (!lesRight && isGreater){

						znA=1;

						znB=0;

					}

					else

					{

						znA=0;

						znB=1;

					}

				}

				else{

					znA=1-znB;

					if (!(znA>=forA[0] && znA<=forA[1]))

						znA=znB;

				}

			}

			else {

				if (znB==-1){

					znB=1-znA;

					if (!(znB>=forB[0] && znB<=forB[1]))

						znB=znA;

				}

			}



			if (znB>znA)

				isGreater=true;



			if (znB<right[i])

				lesRight=true;



			if (znA>left[i])

				moreLeft=true;

			a[i]=znA;

			b[i]=znB;

		}



		for (int i=0; i<KOL_BIT; i++){

			a[i]=a[i]^b[i];

		}



		long result=0;

		for (int i=0; i<KOL_BIT; i++){

			if (a[i]!=0){

				mask=(long)1<<i;

				result+=mask;

			}

		}

		pw.println(result);

		pw.flush();

		pw.close();

	}



}

