    public static void main(String[] args) {

        try {

            BufferedReader in = new BufferedReader(new InputStreamReader(System.in));

            String[] temp = in.readLine().split(" ");

            long L = Long.parseLong(temp[0]);

            long R = Long.parseLong(temp[1]);



            if (L == R) {

                System.out.println(0);

            } else {

                dp = new long[64][2][2][2][2];

                l = convert(L);

                r = convert(R);

                if (r.length() > l.length()) {

                    while (r.length() > l.length()) {

                        l = '0' + l;

                    }

                }

                for (int i = 0; i < dp.length; i++) {

                    for (int j = 0; j < dp[0].length; j++) {

                        for (int k = 0; k < dp[0][0].length; k++) {

                            for (int m = 0; m < dp[0][0][0].length; m++) {

                                for (int n = 0; n < dp[0][0][0][0].length; n++) {

                                    dp[i][j][k][m][n] = -1;

                                }

                            }

                        }

                    }

                }

                long result = cal(0, 0, 0, 0, 0);

                System.out.println(result);

            }

            // System.out.println(l + " " + r);



        } catch (Exception ex) {

            ex.printStackTrace();

        }

    }



    public static long cal(int p, int AcL, int AcR, int BcL, int BcR) {

        if (p == l.length()) {

            return 0;

        }

        if (dp[p][AcL][AcR][BcL][BcR] != -1) {

            return dp[p][AcL][AcR][BcL][BcR];

        }

        int min1 = 0, max1 = 1;

        if (AcL == 0 && l.charAt(p) == '1') {

            min1 = 1;

        }

        if (AcR == 0 && r.charAt(p) == '0') {

            max1 = 0;

        }

        int min2 = 0, max2 = 1;

        if (BcL == 0 && l.charAt(p) == '1') {

            min2 = 1;

        }

        if (BcR == 0 && r.charAt(p) == '0') {

            max2 = 0;

        }

        long result = 0;

        for (int i = min1; i <= max1; i++) {

            for (int j = min2; j <= max2; j++) {

                long v = i ^ j;

                if (v == 1) {

                    //reverse , as this p is the position from left to right

                    v = 1L << (r.length() - p - 1);

                }

                // System.out.println(val);

                int acL = AcL, acR = AcR, bcL = BcL, bcR = BcR;

                if (i == 1 && l.charAt(p) == '0') {

                    acL = 1;

                }

                if (i == 0 && r.charAt(p) == '1') {

                    acR = 1;

                }

                if (j == 1 && l.charAt(p) == '0') {

                    bcL = 1;

                }

                if (j == 0 && r.charAt(p) == '1') {

                    bcR = 1;

                }

                long total = v + cal(p + 1, acL, acR, bcL, bcR);

                result = Math.max(total, result);

            }

        }

        dp[p][AcL][AcR][BcL][BcR] = result;

        return result;

    }



    public static String convert(long val) {

        StringBuilder builder = new StringBuilder();

        while (val > 0) {

            if ((val & 1) == 1) {

                builder.insert(0, '1');

            } else {

                builder.insert(0, '0');

            }

            val >>= 1;

        }

        return builder.toString();

    }

}

