    static class DLittleGirlAndMaximumXOR {
        public void solve(int testNumber, ScanReader in, PrintWriter out) {
            long l = in.scanLong();
            long r = in.scanLong();

            long dif = r - l;
            long two = 1;
            long ans = 0;
            long pos = 0;
            while (dif >= two) {
                ans += two;
