class Program

{

    private final FastBufferReader in;

    private final StringBuilder resBuilder;



    public Program(FastBufferReader in, StringBuilder resBuilder)

    {

        this.in = in;

        this.resBuilder = resBuilder;

    }



    void run()

    {

        long lowLim = in.nextLong();

        long highLim = in.nextLong();



        int i;



        for (i = 62; i >= 0; i--)

        {

            if (getBit(lowLim, i) != getBit(highLim, i))

                break;

        }



        resBuilder.append((1L << (i + 1)) - 1).append("\n");

    }



    private int getBit(long n, int i)

    {

        return (int)((n >> i) & 1);

    }

}

