	static long[][][][][] dp;
	static String s1, s2;
	static int len;

	static String getBinaryString(long num){
		String res = "";
		long tnum = num;
		while(num>0){
			res = (num%2) + res;
			num/=2;
		}
		// System.out.println(tnum+" - "+res);
		return res;
	}

	static long rec(int p, int fl1, int fl2, int fr1, int fr2){
		if(p==len) return 0;

		if(dp[p][fl1][fl2][fr1][fr2] != -1)
			return dp[p][fl1][fl2][fr1][fr2];

		int min1=0, max1=1;
		if(fl1==0 && s1.charAt(p)=='1') min1=1;
		if(fl2==0 && s2.charAt(p)=='0') max1=0;

		int min2=0, max2=1;
		if(fr1==0 && s1.charAt(p)=='1') min2=1;
		if(fr2==0 && s2.charAt(p)=='0') max2=0;

		long res = 0L;
		for(int i=min1;i<=max1;i++){
			for(int j=min2;j<=max2;j++){
				long toadd=0;
				int cur = i^j;
				if(cur==1){
					toadd = (1L << (len-p-1));
				}
				int nfl1=fl1, nfl2=fl2, nfr1=fr1, nfr2=fr2;
				if(i > (s1.charAt(p)-'0'))
					nfl1 = 1;
				if(i < (s2.charAt(p)-'0'))
					nfl2 = 1;
				if(j > (s1.charAt(p)-'0'))
					nfr1 = 1;
				if(j < (s2.charAt(p)-'0'))
					nfr2 = 1;

				long res1 = toadd + rec(p+1, nfl1, nfl2, nfr1, nfr2);
				res = Math.max(res, res1);
			}
		}
		return dp[p][fl1][fl2][fr1][fr2] = res;		
	}

