public class A {

	static class pair implements Comparable<pair> {
		int x;
		int y;

		public pair(int d, int k) {
			x = d;
			y = k;
		}

		@Override
		public int compareTo(pair arg0) {
			// TODO Auto-generated method stub
			if (x == arg0.x) {
				return y - arg0.y;
			}
			return x - arg0.x;
		}
	}

	static PrintWriter pw;
	static int n;
	static int m;
	static int k;

	static ArrayList<Integer> a;

	static int bin(int x) {
		int s = 0;
		int e = a.size() - 1;
		int ans = -1;
		while (s <= e) {
			int mid = (s + e) / 2;
			if (a.get(mid) <= x) {
				s = mid + 1;
				ans = mid;
			} else
				e = mid - 1;
		}
		return ans;
	}

	public static void main(String[] args) throws NumberFormatException, IOException {
		// TODO Auto-generated method stub
		BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
		pw = new PrintWriter(System.out);
		StringTokenizer st = new StringTokenizer(br.readLine());
		long m = Long.parseLong(st.nextToken());
		long n = Long.parseLong(st.nextToken());

		if (m == n)
			pw.println(0);
		else {
			char[] a = Long.toBinaryString(n).toCharArray();
			char[] b = Long.toBinaryString(m).toCharArray();
			char[] c = new char[a.length];
			int i = a.length - 1;
			for (int j = b.length - 1; j >= 0; j--, i--) {
				c[i] = b[j];
			}

			for (; i >= 0; i--)
				c[i] = '0';
			i = 0;
			for (i = 0; i < a.length; i++) {
				if (a[i] != c[i]) {
					break;
				}
			}
			System.out.println(pow(2,a.length-i) - 1);
		}
		pw.flush();
		pw.close();

	}

	static long pow(long a, long e) // O(log e)
	{
		long res = 1;
		while (e > 0) {
			if ((e & 1) == 1)
				res *= a;
			a *= a;
			e >>= 1;
		}
		return res;
	}

	static long gcd(long a, long b) {
		if (b == 0)
			return a;
		return gcd(b, a % b);
	}

}

