public class D276_DP implements Runnable {

    private static final int MAX = (int) (1E5 + 5);
    private static final int MOD = (int) (1E9 + 7);
    private static final int Inf = (int) (1E9 + 10);
    char[] s1;
    char[] s2;
    int len;
    long[][][][][] dp = new long[100][2][2][2][2];
    private void solve() throws IOException {
        long l = reader.nextLong();
        long r = reader.nextLong();
        for(int i=0;i<100;i++)
            for(int j=0;j<2;j++)
                for(int k=0;k<2;k++)
                    for(int m = 0;m<2;m++)
                        for(int n =0;n<2;n++)
                            dp[i][j][k][m][n]= -1L;

        char[] temp = Long.toBinaryString(l).toCharArray();
        s2 = Long.toBinaryString(r).toCharArray();

        if(temp.length > s2.length){
            temp = swap(s2, s2 = temp);
        }


        len = s2.length;
        s1 = new char[len];
        int k =0;
        while(k < s2.length - temp.length){
            s1[k++]='0';
        }
        for(int l1=0;l1 < temp.length;l1++)s1[k++]= temp[l1];

        writer.print(rec(0,0,0,0,0));
    }

    private long DP(int p, int fl1, int fr1, int fl2, int fr2) {

        if( p == len)
            return 0 ;
        if(dp[p][fl1][fr1][fl2][fr2] !=-1)
            return dp[p][fl1][fr1][fl2][fr2];

        int min1 = 0, max1 =0;

        if(fl1 == 0 && s1[p] =='1')
            min1 =1;

        if(fr1 == 0 && s2[p] == '0')
            max1 = 0;

        int min2 =0, max2 =1;
        if(fl2 == 0 && s1[p] == '1')
            min2 =1;
        if(fr2 == 0 && s2[p] == '0')
            max2 =0;
        long res = 0;
        for(int i = min1 ; i<=max1 ;i++)
            for(int j = min2 ; j<=max2;j++){
                int v = i^j;
                int todo =0;
                if(v ==1){
                    todo = 1<<(len-p-1);
                }
                int nfl1 = fl1, nfr1 = fr1, nfl2 = fl2, nfr2 = fr2;
                if( i > s1[p] - '0')
                    nfl1 = 1;
                if(i < s2[p] - '0')
                    nfr1=1;
                if(j > s1[p] - '0')
                    nfl2 = 1;
                if(j < s2[p] - '0')
                    nfr2 = 1;
                long res1 = todo + DP(p+1, nfl1,nfr1, nfl2,nfr2);
                res = Math.max(res, res1);
            }
        return dp[p][fl1][fr1][fl2][fr2] = res;
    }

    long rec(int p, int fl1, int fl2, int fr1, int fr2)
    {
        if (p==len)
            return 0;
        if (dp[p][fl1][fl2][fr1][fr2] != -1)
            return dp[p][fl1][fl2][fr1][fr2];
        int min1 = 0, max1 = 1;
        if ((fl1 == 0) && (s1[p] == '1'))
            min1 = 1;
        if ((fl2 == 0) && (s2[p] == '0'))
            max1 = 0;
        int min2 = 0, max2 = 1;
        if ((fr1 == 0) && (s1[p] == '1'))
            min2 = 1;
        if ((fr2 == 0) && (s2[p] == '0'))
            max2 = 0;
        long res = 0;
        for (int i=min1; i<=max1; ++i)
            for (int j=min2; j<=max2; ++j)
            {
                int v = (i ^ j);
                long toadd = 0;
                if (v == 1) {
                    int step = len - p - 1;
                    toadd = (1L << step);
                }
                int nfl1 = fl1, nfl2 = fl2, nfr1 = fr1, nfr2 = fr2;
                if (i > s1[p] - '0')
                    nfl1 = 1;
                if (i < s2[p] - '0')
                    nfl2 = 1;
                if (j >s1[p] - '0')
                    nfr1 = 1;
                if (j < s2[p]- '0')
                    nfr2 = 1;
                long res1= toadd + rec(p + 1, nfl1, nfl2, nfr1, nfr2);
                res = Math.max(res,res1);
            }
        return dp[p][fl1][fl2][fr1][fr2] = res;
    }

    private char[] swap(char[] s2, char[] chars) {
        return  s2;
    }

