            x = ix;
            y = iy;
            z = iz;
        }
    }

    public void solve() throws IOException{

        long l = in.nextLong();
        long r = in.nextLong();


        long diff = r - l;
        long res = 0L;
        long pos = 0L;

        while(diff >= (1L << pos)){
            res += (1L << pos);
            pos++;
        }

        while((1L << pos) <= r){

            if((((l >> pos) ^ (r >> pos)) & 1L) == 1L){
                res += (1L << pos);
            }
            pos++;
        }

        out.println(res);

        return;
    }



}

