import java.math.BigInteger;
import java.util.Scanner;

public class Solution {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        BigInteger x = sc.nextBigInteger();
        BigInteger y = sc.nextBigInteger();


        if(x.equals(y)){
            System.out.println(0);
            return;
        }

        // get 1st set bit position ||         // get the no of bits in the numbers
        int firstSetBitPosX = 0;
        int firstSetBitPosY = 0;
        BigInteger tempX = x;
        BigInteger tempY = y;
        while(tempX.getLowestSetBit() != -1){
            firstSetBitPosX++;
            tempX = tempX.shiftRight(1);
        }
        while(tempY.getLowestSetBit() != -1){
            firstSetBitPosY++;
            tempY = tempY.shiftRight(1);
        }


        // flips between since 1st bit
        int bitsToCheck = Math.max(firstSetBitPosX,firstSetBitPosY);
        int firstDiffBit = firstSetBitPosY;
        if(firstSetBitPosX == firstSetBitPosY){
            //find the 1st diff bit pos;
            while(x.getLowestSetBit() > -1){
                int bitx = x.testBit(firstDiffBit) ? 1 : 0;
                int bity = y.testBit(firstDiffBit) ? 1 : 0;
                if(bitx == bity){
                    firstDiffBit--;
                }
                else{
                    bitsToCheck = firstDiffBit;
                    break;
                }
            }
        }
        else{
            bitsToCheck = firstDiffBit;
        }
        while(bitsToCheck-- > 0){
            int bitX = x.testBit(bitsToCheck) ? 1 : 0;
            int bitY = y.testBit(bitsToCheck) ? 1 : 0;
            if((bitX ^ bitY ) != 1){
                if(bitX == 0)
                    x = x.flipBit(bitsToCheck);
                else
                    y = y.flipBit(bitsToCheck);
            }
        }
        System.out.println(x.xor(y));



    }
}

