    public static long mod = 17352642619633L;

    long L;
    long R;
    void run(FastScanner in, PrintWriter out) {

        L = in.nextLong();
        R = in.nextLong();

        out.println(go(L, R, 61));
    }

    long go(long l, long r, int index) {
        if (index < 0) return 0;
        long mask = 1L<<index;

        if ((l&mask) == (r&mask)) {
            long max = 0;
            if (((l^mask) >= L) && ((l^mask) <= R)) {
                max = mask | go(l^mask, r, index-1);
            }
            else if (((r^mask) >= L) && ((r^mask) <= R)) {
                max = Math.max(max, mask | go(l, r^mask, index-1));
            }
            if (max > 0) return max;
            return go(l, r, index-1);
        }

        return mask | go(l, r, index-1);
    }

    static class FastScanner {
        BufferedReader br;
        StringTokenizer st;

        public FastScanner(InputStream in) {
            br = new BufferedReader(new InputStreamReader(in));
            st = null;
        }

        String next() {
            while (st == null || !st.hasMoreElements()) {
                try {
                    st = new StringTokenizer(br.readLine());
                } catch (IOException e) {
                    e.printStackTrace();
                }
            }
            return st.nextToken();
        }

