public class TaskB {

	public FasterScanner mFScanner;
	public PrintWriter mOut;

	public TaskB() {
		mFScanner = new FasterScanner();
		mOut = new PrintWriter(System.out);
	}

	public void solve() {
		long n, k;

		n = mFScanner.nextLong();
		k = mFScanner.nextLong();

		long max;

		max = k * (k - 1);
		max /= 2;
		max++;

		if (max < n) {
			mOut.println(-1);
			return;
		}

		if (n == 1) {
			mOut.println(0);
			return;
		}

		long low = 1;
		long high = k;
		long mid;
		long tempVar;
		long var = 2 * (max - n);
		long res = -1;

		while (low <= high) {

			mid = (low + high) / 2;

			tempVar = mid * (mid - 1);

			if (tempVar >= var) {
				high = mid - 1;
				res = k - mid;
				if (tempVar != var)
					res++;
			} else {
				low = mid + 1;
			}
		}

		mOut.println(res);

	}

	public void flush() {
		mOut.flush();
	}

	public void close() {
		mOut.close();
	}

