import java.util.Scanner;

public class Algo {

    static long sum(long num) {

        return (num*(num+1)) / 2;
    }

    static long summ(long low , long high ) {
        if(low <=1 )
            return sum(high);
        return sum(high)-sum(low-1);
    }
    static long binarySearch(long k , long n){

        long start = 1;
        long end = k;

        while(start < end){
            long mid = (start+end)/2;
            long sum = summ(mid,k);

            if(sum==n)
                return k - mid + 1;
            if(sum > n)
                start = mid + 1;
            else
                end = mid;

        }
        return k - start + 1 + 1;
    }
    public static void main(String[] args) {


        Scanner sc = new Scanner(System.in);
        long n = sc.nextLong();
        long k = sc.nextLong();

        if( n == 1 )
            System.out.println(0);
        else if ( n <= k)
            System.out.println(1);

        else {
            n--;
            k--;

            if( sum(k) < n )
                System.out.println(-1);
            else
                System.out.println(binarySearch(k, n));
        }


    }


}

