        public void run() {
            long n = in.nextLong();
            long k = in.nextLong();
            if(n==1){
                out.println(0);
            } else if (n<=k){
                out.println(1);
            } else if(n>f(k)) {
                out.println(-1);
            } else {
                long l = 1;
                long r = k;
                long m = 0;
                long a = 0;
                while(l<=r){
                    m = (l+r)/2;
                    long p = f(k)-f(k-m) + 1;
                    if(p>n){
                        r = m-1;
                    } else {
                        l = m+1;
                        a = m + (p==n?0:1);
                    }
                }
                out.println(a);
            }
        }

        private long f(long k) {
            if(k<=0) return 0;
            return (k*(k+1))/2 - k +1;
        }

    }

