	private static long binarysearch(long n, long k, long i, long j) {

		if(j - i <= 1) {

			return i;

		}

		long m = (i+j)/2;

		if(n > k*(k+1)/2 - m *(m+1)/2) {

			return binarysearch(n,k,i,m);

		}else

			return binarysearch(n,k,m,j);

	}



