  static class dsu {
    int parent[];

    dsu(int n) {
      parent = new int[n];
      for (int i = 0; i < n; i++)
        parent[i] = -1;
    }

    int find(int a) {
      if (parent[a] < 0)
        return a;
      else {
        int x = find(parent[a]);
        parent[a] = x;
        return x;
      }
    }

    void merge(int a, int b) {
      a = find(a);
      b = find(b);
      if (a == b)
        return;
      parent[b] = a;
    }
  }

