    private void init() throws Exception {

        in = new InputReader(onlineJudge ? System.in : new FileInputStream(new File("in.txt")));

        out = new PrintWriter(System.out);

        sb = new StringBuilder();

    }



    private int check(long kp, long k, long n) {

        long max = k + ((2 * k - kp - 2) * (kp - 1)) / 2;

        long min = 2 + ((2 + kp) * (kp - 1)) / 2;

        if (n > max) return 1;

        else if (n < min) return -1;

        else return 0;

    }



    private long bs(long n, long k) {

        long l = 0, r = k, m, ans = -1;

        while (l <= r) {

            m = (l + r) >> 1;

            int check = check(m, k, n);

            if (check == 0) {

                ans = m;

                r = m - 1;

            } else if (check == -1) {

                r = m - 1;

            } else {

                l = m + 1;

            }

        }

        return ans;

    }



    private void solve() throws Exception {

        long n = in.nextLong(), k = in.nextLong();

        sb.append(bs(n, k));

    }



    class InputReader {

        private int lenbuf = 0, ptrbuf = 0;

        private InputStream in;

        private byte[] inbuf = new byte[1024];



        InputReader(InputStream in) {

            this.in = in;

        }



        private int readByte() {

            if (lenbuf == -1) throw new InputMismatchException();

            if (ptrbuf >= lenbuf) {

                ptrbuf = 0;

                try {

                    lenbuf = in.read(inbuf);

                } catch (IOException e) {

                    throw new InputMismatchException();

                }

                if (lenbuf <= 0) return -1;

            }

            return inbuf[ptrbuf++];

        }



        private boolean isSpaceChar(int c) {

            return !(c >= 33 && c <= 126);

        }



        private int skip() {

            int b;

            while ((b = readByte()) != -1 && isSpaceChar(b)) ;

            return b;

        }



        int nextInt() {

            int num = 0, b;

            boolean minus = false;

            while ((b = readByte()) != -1 && !((b >= '0' && b <= '9') || b == '-')) ;

            if (b == '-') {

                minus = true;

                b = readByte();

            }



            while (true) {

                if (b >= '0' && b <= '9') {

                    num = num * 10 + (b - '0');

                } else {

                    return minus ? -num : num;

                }

                b = readByte();

            }

        }



        long nextLong() {

            long num = 0;

            int b;

            boolean minus = false;

            while ((b = readByte()) != -1 && !((b >= '0' && b <= '9') || b == '-')) ;

            if (b == '-') {

                minus = true;

                b = readByte();

            }



            while (true) {

                if (b >= '0' && b <= '9') {

                    num = num * 10 + (b - '0');

                } else {

                    return minus ? -num : num;

                }

                b = readByte();

            }

        }



        double nextDouble() {

            return Double.parseDouble(next());

        }



        char nextChar() {

            return (char) skip();

        }



        String next() {

            int b = skip();

            StringBuilder sb = new StringBuilder();

            while (!(isSpaceChar(b))) {

                sb.appendCodePoint(b);

                b = readByte();

            }

            return sb.toString();

        }



        String nextLine() {

            int b = skip();

            StringBuilder sb = new StringBuilder();

            while (!(isSpaceChar(b) && b != ' ')) {

                sb.appendCodePoint(b);

                b = readByte();

            }

            return sb.toString();

        }



        char[] nextCharArray(int n) {

            char[] buf = new char[n];

            int b = skip(), p = 0;

            while (p < n && !(isSpaceChar(b))) {

                buf[p++] = (char) b;

                b = readByte();

            }

            return n == p ? buf : Arrays.copyOf(buf, p);

        }



        char[][] nextCharMatrix(int n, int m) {

            char[][] map = new char[n][];

            for (int i = 0; i < n; i++) map[i] = nextCharArray(m);

            return map;

        }



        int[][] nextIntMatrix(int n, int m) {

            int[][] map = new int[n][];

            for (int i = 0; i < n; i++) map[i] = nextIntArray(m);

            return map;

        }



        int[] nextIntArray(int n) {

            int[] a = new int[n];

            for (int i = 0; i < n; i++) a[i] = nextInt();

            return a;

        }

    }

}

