class TaskB {
    public void solve(int testNumber, InputReader in, PrintWriter out) {
        long N = in.nextLong();
        long K = in.nextLong();

        if(N == 1) {
            out.println(0);
            return;
        }
        if(N <= K) {
            out.println(1);
            return;
        }

        long st = 1;
        long dr = K - 1;
        long m;
        long ans = -1;

        while(st <= dr) {
            m = (st + dr) / 2;

            if(get(m, K) <= N) {
                ans = m;
                st = m + 1;
            }
            else dr = m - 1;
        }

        N -= get(ans, K);

        if(ans == -1 || (ans == K - 1 && N > 0) ) {
            out.println(-1);
            return;
        }
        if(N > 0)
            ans++;

        out.println(ans);
    }

    private long get(long p, long K) {
        long sum = (K - p + 1 + K) * p / 2;
        long extra = p - 1;
        return sum - extra;
    }
}

class InputReader {
