    public void solve(int testNumber, Scanner in, PrintWriter out) {

        long n = in.nextLong();

        long k = in.nextLong();

        if (n == 1) {

            out.println(0);

            return;

        }

        if (k * (k - 1) < 2 * (n - 1)) {

            out.println(-1);

            return;

        }



        long sq2 = 4 * k * k - 4 * k + 1 - 4 * (2 * n - 2);

        long km = Math.max(2, (long) ((Math.sqrt(sq2) + 3) / 2.0) - 3);

        while (((km + k - 2)*(k - km + 1) >= 2*(n-1))) {

            ++km;

        }

        out.println(k - km + 2);

    }

