public class P287B_Pipeline {



    public static void main(String[] args) throws IOException {

        BufferedReader in = new BufferedReader(new InputStreamReader(System.in));

        String[] line = in.readLine().split(" ");

        long n = Long.parseLong(line[0]);

        long k = Long.parseLong(line[1]);

        System.out.println(res(n,k));

    }



    public static long cnt(long l, long k) {

        return (k - 1 + l - 1)*(k - l + 1)/2 + 1;

    }



    public static long res(long n, long k) {

        if (n == 1) return 0;

        if (n <= k) return 1;

        long max = k*(k-1)/2 + 1;

        if (max < n) return -1;

        long left = 2;

        long right = k;

        while (left <= right) {

            long l = (left + right) / 2;

            long c = cnt(l,k);

            if (c < n) {

                right = l - 1;

            } else if (c > n) {

                left = l + 1;

            } else {

                return k-l+1;

            }

        }

        return k-right+1;

    }



}

