	private static void solve() throws IOException

	{

		Long n = in.nextLong();

		Long k = in.nextLong();

		if (n == 1) {

			out.println(0);

			return;

		}



		Long left = 2L;

		Long right = k;

		Long totSplitter = 0L;

		Long minAns = Long.MAX_VALUE;

		Long mid;

		while (true) {

			mid = (left + right) / 2;

			totSplitter = GetOut(mid, k);

			if (totSplitter >= n) {

				left = mid + 1;

				minAns = Math.min(minAns, k - mid + 1);

			}

			else {

				right = mid - 1;

			}

			if (left > right)

				break;

		}

		if (minAns == Long.MAX_VALUE)

			out.println(-1);

		else

			out.println(minAns);

	}



	static long GetOut(long k1, long k)

	{

		return k1 + (k1 + k - 1) * (k - k1) / 2;

	}



