        long n = in.nextLong();

        if (n == 1) {

            out.print(0);

            return;

        }

        long k = in.nextLong();



        if (n <= k) {

            out.print(1);

            return;

        }



        if (k * (k - 1) / 2 + 1 < n) {

            out.print(-1);

            return;

        }



        long i = 1;

        long j = k;

        while (i < j - 1) {

            long m = (j + i) / 2;

            if ((k - m + 1) * (k + m) / 2 - (k - m) <= n)

                j = m;

            else

                i = m;

        }

        if ((k - j + 1) * (k + j) / 2 - (k - j) >= n)

            out.print(k - j + 1);

        else

            out.print(k - i + 1);

    }

