	static boolean valid(long numberUsed) {	
		long st=k-numberUsed;

		if(st==1)return total>=n;
		long start=((st)*(st+1))/2+1;

		return total-start>=n;
	}


	static long BS() {
		if(n==1)return 0;
		if(k>=n)return 1;
		if(total<n)return -1;
		if(total==n)return k-1;

		long st = 2,end=k,mid=0;	

		while(st<=end) {		
			// i make a binary search over the number of the pipelines needed to be used..
			mid = (st+end)/2;
			if(valid(mid))end=mid-1;			// if it is valid so we can minimize more so that i make end= make-1
			else st=mid+1;

		}
		return end;
	}





















