class TaskB {

    public void solve(int testNumber, InputReader in, OutputWriter out) {

        long count = in.readLong();

        long pipeLine = in.readLong();



        if (count == 1) {

            out.printLine(0);

            return;

        }



        if (pipeLine >= count) {

            out.printLine(1);

            return;

        }



        if (pipeLine * (pipeLine + 1) < (count + pipeLine - 1) * 2) {

            out.printLine(-1);

            return;

        }



        long left = 1;

        long right = pipeLine;

        while (right - left > 1) {

            long mid = ((right + left) >> 1);

            if (count - (sumSegment(mid, pipeLine) - (pipeLine - mid)) < mid - 1)

                left = mid;

            else

                right = mid;

        }



        long answer = 0;

        if (count - (sumSegment(left, pipeLine) - (pipeLine - left)) < left - 1)

            answer = pipeLine - left + 2;

        if (count - (sumSegment(right, pipeLine) - (pipeLine - right)) < right - 1)

            answer = pipeLine - right + 2;



        out.printLine(answer);

    }



    private long sumSegment(long x, long y) {

        long cur = y - x + 1;

        return  ((x - 1) * (y - x + 1) + (cur * (cur + 1)) / 2);

    }

}



class InputReader {

    private InputStream stream;

    private byte[] buf = new byte[1024];

    private int curChar;

    private int numChars;

    private SpaceCharFilter filter;



    public InputReader(InputStream stream) {

        this.stream = stream;

    }



    public int read() {

        if (numChars == -1)

            throw new InputMismatchException();

        if (curChar >= numChars) {

            curChar = 0;

            try {

                numChars = stream.read(buf);

            } catch (IOException e) {

                throw new InputMismatchException();

            }

            if (numChars <= 0)

                return -1;

        }

        return buf[curChar++];

    }



    public boolean isSpaceChar(int c) {

        if (filter != null)

            return filter.isSpaceChar(c);

        return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1;

    }



    public long readLong() {

        int c = read();

        while (isSpaceChar(c))

            c = read();

        int sgn = 1;

        if (c == '-') {

            sgn = -1;

            c = read();

        }

        long res = 0;

        do {

            if (c < '0' || c > '9')

                throw new InputMismatchException();

            res *= 10;

            res += c - '0';

            c = read();

        } while (!isSpaceChar(c));

        return res * sgn;

    }



    public interface SpaceCharFilter {

        public boolean isSpaceChar(int ch);

    }



    }



