public class Main {
    static Reader in = null;
    static PrintWriter out = null;

    static long sum(long s, long e) {
        return (e * (e-1) / 2) - (s * (s-1) / 2) + s;
    }

    static void solve() throws IOException {
        long n = in.nextLong();
        long k = in.nextLong();
        if(n == 1) {
            out.println(0);
            return;
        }
        long ans = 0;
        while(n != 0) {
            long l = Math.min(n, k);
            long s = 2, e = l, x = -1;
            while(s <= e) {
                long m = (s+e)/2;
                long t = sum(m, l);
                if(t <= n) {
                    x = m;
                    e = m-1;
                }
                else s = m+1;
            }
            if(x == 2 && sum(x, l) != n) break;
            n = n - sum(x, l);
            ans = ans + (l - x + 1);
            if(n == 1) {
                ans++;
                n--;
            }
        }
        if(n == 0) out.println(ans);
        else out.println(-1);
    }

    public static void main(String[] args) {
        try {
            OutputStreamWriter osw = new OutputStreamWriter(System.out);
            BufferedWriter bw = new BufferedWriter(osw);
            in = new Reader();
            out = new PrintWriter(bw);

            solve();

            out.close();
            bw.close();
            osw.close();
            in.close();
        }
        catch (IOException e) {
            e.printStackTrace();
        }
    }

