    private static long countSplitters(long k, long n) {
        long start = 1, end = k;
        while (start < end) {
            long mid = (start + end) / 2;

            long sum = sum(mid, k);

            if (sum == n)
                return k - mid + 1;
            if (sum > n) {
                start = mid + 1;
            } else {
                end = mid;
            }

        }

        return k - start + 2;

    }

