public final class Solution {
    public static void main(String[] args) {
        Scanner s = new Scanner(System.in);

        long n = s.nextLong();
        long k = s.nextLong();

        long answer = 0;
        long total = (long) (Math.pow(k, 2) + k) / 2 - (k - 1);

        if (n == k || k > n) {
            answer = 1;
            if (n == (long) 1) {
                answer = 0;
            }
        } else if (n > total) {
            answer = -1;
        } else if (n == total) {
            answer = k - 1;
        } else {
            long in1 = 1;
            long in2 = 1;
            long limit1 = 2;
            long limit2 = k;
            long a = (limit2 - limit1) / 2 + limit1;
            while (!(in1 >= n && in2 < n)) {

                a = (limit2 - limit1) / 2 + limit1;
                if ((limit2 - limit1) % 2 != 0) a++;
                long a1 = a;
                long a2 = a + 1;
                in1 = (long) ((a1 * (a1 + 1))) / 2 - (a1 - 1);
                in1 = total - in1 + 1;
