public class Pipeline {

    public static long sumOfPipes(long n, long k) {

        long left = 1;
        long right = k;

        while (left < right) {
            long mid = (left + right) / 2;
            long s = sum(mid, k);
            if (s == n) {
                return k - mid + 1;
            } else if (s > n) {
                left = mid + 1;
            } else {
                right = mid;
            }
        }

        return k - left + 2;
    }

    static long sum(long left, long right) {
        long s = 0;
        if (left <= right) {
            s = sum(right) - sum(left - 1);
        }
        return s;
    }

    static long sum(long k) {
        return k * (k + 1) / 2;
    }

