			sum *= (k1 -1 + k1 - k2);

			sum = (sum/ 2) + 1;

			return sum;

		}

	}



	private static long bs(long start, long end, long req, int k)

	{

		long med = (start + end) / 2;



		while (start <= end)

		{

			 med = (start + end) / 2;

			long medVal = maxK(k, (int) med);

			long prevVal = maxK(k, (int) (med - 1));

			if (medVal >= req && prevVal < req)

				return med;

			else if (medVal < req)

				start = med + 1;

			else

				end = med - 1;

		}



		return med;

	}







