            System.out.println("0");
            return;
        }

        long result = minSplitters();
//        System.out.println("--------------------");
        if(result >= k){
            System.out.println(-1);
        }else{
            System.out.println(result);
        }
    }

    private static long minSplitters() {
        long result = -1;
        long start = 1, end = k-1, mid;
        mid = (start + end)/2;
        while(start <= end && mid >= start && mid <= end){
//            System.out.println("result: "+result);
            myListCheck = new HashMap<>();
            myList = new ArrayList<>();
//            System.out.println("start: "+start+"  , end: "+end+"  , mid: "+mid);

            long value = (k*(k+1))/2 - ((k-mid)*((k-mid)+1))/2 - (mid-1);
//            System.out.println("value: "+value);
            long key;
            if(value < n){
                key = 1;
            }else if(value > n){
                key = -1;
            }else{
                key = 0;
            }

//            System.out.println("key: "+key);
            if(key == 1){
                start = mid+1;
                mid = (start + end)/2;
            }else{
                if(mid < k && mid >= 1){
