public class A {
    private static final int mod = (int)1e9+9;

    final IOFast io = new IOFast();

    long k;

    boolean ok(long n, long m, long x) {
        long u = k * x;
        long val = u;
        val += (m - u) / (k - 1) * k;

        if((m - u) % (k - 1) == 0) val -= 1;
        else val += (m - u) % (k - 1);

        return val <= n;
    }

    long rec(long n, long m, long cur) {
        long pow = 1;
        long p = 1000;
        for(int i = 0; i < p; i++) pow = pow * 2 % mod;
        while(true) {
            if(ok(n, m, 0)) { return (m + cur) % mod; }
            if(!ok(n - p * k, m - p * k, p)) {
                n -= p * k;
                m -= p * k;
                cur = cur * pow % mod;
                cur += (pow - 1) * 2 * k % mod;
                cur %= mod;
                continue;
            }
            n -= k;
            m -= k;
            cur += k;
            cur = cur * 2 % mod;
//          System.err.println(cur);
        }
    }

    public void run() throws IOException {
        long n = io.nextLong();
        long m = io.nextLong();
        k = io.nextLong();
        io.out.println(rec(n, m, 0));
        if(true) return;

        long low = -1, high = m / k + 1;
        while(high - low > 1) {
            long mid = (low + high) / 2;

            if(!ok(n, m, mid)) {
                low = mid;
            }
            else {
                high = mid;
            }
//          System.err.println(mid + " " + (u + (m - u - k) / (k - 1) * k + k - 1 + (m - u) % (k - 1)) + " " + n);
        }

        long pow = powmod(2, high, mod);
        long score = m - high * k;
        score = (score + (pow - 1) * 2 * k) % mod;
        io.out.println(score);
    }


    static long powmod(long n, long r, int m) {
        long res = 1;
        for(; r != 0; r >>>= 1, n = n * n % m) {
            if((r&1) == 1) {
                res = res * n;
                if(res >= m) {
                    res %= m;
                }
            }
        }
        return res;
    }

