//        out.println("mTmp=" + mTmp + "Full: " + fullC);

        long pow2 = getPow(2, fullC + 1, MOD);
        res = (((res + pow2 + MOD - 2) % MOD) * k) % MOD;

//        out.println("After full: " + res);

        mTmp = mTmp % k;
        res = (res + mTmp) % MOD;

        nTmp = n;
        mTmp = m - fullC * k - mTmp;
        tmp = 1024 * 1024;
        while (tmp > 0) {
            while (mTmp >= (k - 1) * tmp && nTmp - k * tmp >= mTmp - (k - 1) * tmp) {
                nTmp -= k * tmp;
                mTmp -= (k - 1) * tmp;
                res = (res + (k - 1) * tmp) % MOD;
            }
            tmp /= 2;
        }
        out.println(res);
