    static long[] pows = new long[1000000];

    public static long getPow(long base, long pow, long mod) {
        if (pow < pows.length && pows[(int) pow] != 0) {
            return pows[(int) pow];
        }
        if (pow == 0) {
            pows[0] = 1;
            return 1;
        }
        if (pow == 1) {
            pows[1] = base;
            return base;
        }
        long res = getPow(base, pow / 2, mod);
        res = (res * res) % mod;
        res = (res * getPow(base, pow % 2, mod)) % mod;
        if (pow < pows.length) {
            pows[(int) pow] = res;
        }
        return res;
    }

