    void solve() throws IOException {
		final int mod = 1000*1000*1000+9;
		long n = readInt();
		long m = readInt();
		long k = readInt();
		long fail = n-m;
		long posl = n / k ;
		if(n % k != 0) {
			posl++;
		}
		if(posl <= fail) {
			out.println(m);
		} else {
			long d = fail - posl;
			long res = (k-1) * fail;
			m -= (k-1) * fail;
			long z = m / k;
			res += m % k;
			res %= mod;
			long x = binpow(2, z+1, mod);
			x -= 2;
			x += mod;
			x %= mod;
			x *= k;
			res += x;
			res %= mod;
			out.println(res);
		}
    }

	long binpow (long a, long n, long mod) {
		long res = 1;
		while (n != 0)
			if ((n & 1) != 0) {
				res *= a;
				res = res % mod;
				--n;
			}
			else {
				a *= a;
				a = a % mod;
				n >>= 1;
			}
		return res;
	}

    void init() throws FileNotFoundException {
        if (ONLINE_JUDGE) {
            in = new BufferedReader(new InputStreamReader(System.in));
            out = new PrintWriter(System.out);
