	long md = (1000 * 1000 * 1000 + 9);

	void solve() throws IOException{
		int n = readInt();
		int m = readInt();
		int k = readInt();

		long count = n / k;
		long mod = n % k;

		long maxM = count * (k - 1) + mod;
		if (maxM >= m) {
			out.println(m % md);
			return;
		}

		long d = m - maxM;
		long mul = (binpow(2, d) - 1 + md) % md * 2 % md;

		long ans = (mul * k) % md;
		ans = (ans + ((count - d) * (k - 1) % md + md) % md + mod) % md;

		out.println(ans);
	}

	long binpow(long a, long n) {
		if (n == 0) return 1;
		if ((n & 1) == 0) {
			long b = binpow(a, n >> 1);
			return (b * b) % md;
		} else {
			return binpow(a, n - 1) * a % md;
		}
	}
