		if (to - from <= 1) {

			return;

		}

		int i = from;

		int j = to - 1;

		long x = a[from + (new Random()).nextInt(to - from)];

		while (i <= j) {

			while (a[i] < x) {

				i++;

			}

			while (a[j] > x) {

				j--;

			}

			if (i <= j) {

				long t = a[i];

				a[i] = a[j];

				a[j] = t;

				i++;

				j--;

			}

		}

