            if (n - digitSum(n) < s) {

                out.println(0);

                return;

            }



            long left = 0;

            long right = n;

            while (left < right) {

                long mid = left + (right - left) / 2;

                if (mid - digitSum(mid) >= s) { // if condition(mid) == true

