	static class InputReader {

        private InputStream stream;

        private byte[] buf = new byte[1024];

        private int curChar;

        private int numChars;

        private SpaceCharFilter filter;



        public InputReader(InputStream stream) {

            this.stream = stream;

        }



        public int read() {

            if (numChars == -1)

                throw new InputMismatchException();



            if (curChar >= numChars) {

                curChar = 0;

                try {

                    numChars = stream.read(buf);

                } catch (IOException e) {

                    throw new InputMismatchException();

                }



                if (numChars <= 0)

                    return -1;

            }

            return buf[curChar++];

        }



        public String nextLine() {

            BufferedReader br = new BufferedReader(new InputStreamReader(System.in));

            String str = "";

            try {

                str = br.readLine();

            } catch (IOException e) {

                e.printStackTrace();

            }

            return str;

        }



        public int nextInt() {

            int c = read();



            while (isSpaceChar(c))

                c = read();



            int sgn = 1;



            if (c == '-') {

                sgn = -1;

                c = read();

            }



            int res = 0;

            do {

                if (c < '0' || c > '9')

                    throw new InputMismatchException();

                res *= 10;

                res += c - '0';

                c = read();

            }

            while (!isSpaceChar(c));



            return res * sgn;

        }



        public long nextLong() {

            int c = read();

            while (isSpaceChar(c))

                c = read();

            int sgn = 1;

            if (c == '-') {

                sgn = -1;

                c = read();

            }

            long res = 0;



            do {

                if (c < '0' || c > '9')

                    throw new InputMismatchException();

                res *= 10;

                res += c - '0';

                c = read();

            }

            while (!isSpaceChar(c));

            return res * sgn;

        }



        public double nextDouble() {

            int c = read();

            while (isSpaceChar(c))

                c = read();

            int sgn = 1;

            if (c == '-') {

                sgn = -1;

                c = read();

            }

            double res = 0;

            while (!isSpaceChar(c) && c != '.') {

                if (c == 'e' || c == 'E')

                    return res * Math.pow(10, nextInt());

                if (c < '0' || c > '9')

                    throw new InputMismatchException();

                res *= 10;

                res += c - '0';

                c = read();

            }

            if (c == '.') {

                c = read();

                double m = 1;

                while (!isSpaceChar(c)) {

                    if (c == 'e' || c == 'E')

                        return res * Math.pow(10, nextInt());

                    if (c < '0' || c > '9')

                        throw new InputMismatchException();

                    m /= 10;

                    res += (c - '0') * m;

                    c = read();

                }

            }

            return res * sgn;

        }



        public String readString() {

            int c = read();

            while (isSpaceChar(c))

                c = read();

            StringBuilder res = new StringBuilder();

            do {

                res.appendCodePoint(c);

                c = read();

            }

            while (!isSpaceChar(c));



            return res.toString();

        }



        public boolean isSpaceChar(int c) {

            if (filter != null)

                return filter.isSpaceChar(c);

            return c == ' ' || c == '\n' || c == '\r' || c == '\t' || c == -1;

        }



        public String next() {

            return readString();

        }



        public interface SpaceCharFilter {

            public boolean isSpaceChar(int ch);

        }

    }

}

import java.util.*;
import java.io.*;
import java.math.*;

public class Main{

  public static boolean check(BigInteger a, BigInteger b){
    long  n = 0;
    String aStr = a.toString();
    for (int i=0; i < aStr.length() ;i++ ) {
      n += Long.valueOf(aStr.charAt(i)-'0');
    }
    return a.subtract(BigInteger.valueOf(n)).compareTo(b) >= 0;
  }

  public static void main(String[] args) {
    try(BufferedReader in = new BufferedReader(new InputStreamReader(System.in))){
      String[] str = in.readLine().split(" ");
      BigInteger n = new BigInteger(str[0]);
      BigInteger s = new BigInteger(str[1]);

      BigInteger left = BigInteger.ONE;
      BigInteger right = new BigInteger(n.toString()).add(BigInteger.TEN);

      BigInteger TWO = BigInteger.ONE.add(BigInteger.ONE);

      BigInteger t;

      while(right.subtract(left).compareTo(BigInteger.ONE)>0){
        t = left.add(right.subtract(left).divide(TWO));
        if(check(t, s)){
          right = t;
        }else{
          left = t;
        }
      }
      BigInteger result = n.subtract(right).add(BigInteger.ONE);
      if (result.compareTo(BigInteger.ZERO)<=0) {
        System.out.println(0);
      }else{
        System.out.println(result);
      }

    }catch (IOException e) {
      e.printStackTrace();
    }
  }
}

