			Arrays.fill(sizeParent,1);

			for(int i=0;i<n;i++)

				parent[i]=i;

		}



		int find(int x)

		{

			if(x!=parent[x])

				parent[x]=find(parent[x]);

			return parent[x];

		}



		void union(int x,int y)

		{

			x=find(x);

			y=find(y);

			if(sizeParent[x]>=sizeParent[y])

			{

				if(x!=y)

					sizeParent[x]+=sizeParent[y];

				parent[y]=x;

			}

			else

			{

				if(x!=y)

					sizeParent[y]+=sizeParent[x];

				parent[x]=y;

			}

		}

	}



