	static long[] extendedEuclid(long A, long B) {

		if(B == 0) {

			long d = A;

			long x = 1;

			long y = 0;

			return new long[]{x,y,d};

		}

		else {

			long arr[]=extendedEuclid(B, A%B);

			long temp = arr[0];

			arr[0] = arr[1];

			arr[1] = temp - (A/B)*arr[1];

			return arr;

