			return;
		}

		long cur = s;
		while (cur <= bound && s + digitSum(cur) > cur) {
			cur++;
		}
		System.out.println(bound - cur + 1);
	}

	static int digitSum(long inp) {
		int sum = 0;
		while (inp != 0) {
			sum += inp % 10;
			inp /= 10;
		}
		return sum;
	}

}

