class myC{
	long MOD = 1000000007;
	long fastPow(long x, long k){
		long bb=x%MOD, ans=1;
		while(k > 0){
			if((k&1)==1){
				ans=(ans*bb)%MOD;
			}
			bb=(bb*bb)%MOD;
			k>>=1;
		}
		return ans;
	}
