public class C extends PrintWriter {

    final long mod = 1_000_000_007;

    long pow(long n, long p) {
        long r = 1;

        while (p > 0) {
            if (p % 2 == 1) {
                r = (r * n) % mod;
            }
            n = (n * n) % mod;
            p /= 2;
        }

        return r;
    }

    long solve(long n, long k) {

        if (k == 0) {
            return (2 * n) % mod;
        }

        if (n == 0) {
            return 0;
        }

        long m = pow(2, k);

        long a = 2;

        a = (a * n) % mod;
        a = (a * m) % mod;

        long b = (m + mod - 1) % mod;

        return ((a - b + mod) % mod);
    }

    void run() {
        long n = nextLong();
        long k = nextLong();

        println(solve(n, k));
    }

    boolean skip() {
        while (hasNext()) {
