        public void solve(int testNumber, MyInput in, PrintWriter out) {
            this.in = in;
            this.out = out;

            n = in.nextInt();

            if (n / 2 % 2 == 1) {
                answer(-1);
                return;
            }

            int low = 0, high = n / 2;
            int diff = query(low + n / 2) - query(low);
            while (diff != 0) {
                int mid = (low + high) / 2;
                int d = query(mid + n / 2) - query(mid);
                if (d == 0 || diff > 0 == d > 0) {
