                        out.println("! " + mid);
                        out.flush();
                        return;
                    } else {
                        if (Integer.signum(a) == Integer.signum(lowVal)) {
                            low = mid + 1;
                        } else {
                            high = mid;
                        }
                    }
                }
                out.println("! " + low);
                out.flush();
            }
        }

        int getval(int i, PrintWriter out, InputReader in) {
            out.println("? " + i);
            out.flush();
            int a = in.nextInt();
            out.println("? " + (i + N / 2));
            out.flush();
            int b = in.nextInt();
            return a - b;
