	void work() {
		long n=in.nextLong();
		long k=in.nextLong();
		if(k==0) {
			out.println("YES"+" "+n);
		}
		long a=0,b=0,c=1,d=1;
		while(--n>=0&&a<=k) {
			b+=c;
			c*=4;
			a+=d;
			d=d*2+1;
			long t=count(c-d,n);
			if(a<=k&&b>=k-t) {
				out.println("YES"+ " "+n);
				return;
			}
		}
		out.println("NO");
	}
	private long count(long l, long n) {
		if(n==0)return 0;
		n--;
		long ret=l;
		for(int i=1;i<=n;i++) {
			long t=ret;
			ret*=4;
			if(ret/4!=t)return Long.MAX_VALUE;
		}
		return ret;
	}
