		int t = fs.nextInt();
		while(t-->0) {
			int n = fs.nextInt();
			long k = fs.nextLong();
			long toCut = 1, numSquares = 1, free = 0;
			int cuts = 0;
			while(true) {
				if(cuts >= n) {
					k = oo;
					break;
				}
				k -= toCut;
				if(k < 0) {
					k = oo;
					break;
				}
				cuts++;
				try {
					free = Math.addExact(free, Math.multiplyExact(numSquares, getVal(n-cuts)));
				} catch (Exception e) {
					k = 0;
					break;
				}
				if(free >= k) {
					k = 0;
					break;
				}
				toCut += (1L<<cuts);
				numSquares += (1L<<(cuts+1));
			}
			if(k == 0) {
				out.printf("YES %d\n", n-cuts);
			}
			else {
				out.printf("NO\n");
			}
		}

