	static long bin(long k) {
		long left = 1;
		long right = k+1;
		long mid;
		long ans = 1;
		while (left <= right) {
			mid = (left + right) / 2;

			if (check(mid, k)) {
				ans = mid;
				left = mid + 1;

			} else
				right = mid - 1;
		}
		return ans;
	}

