			ans = Arre[index - 1];
			if ((index != E + 1))
				ans += (targetleft) ? Arre[index - 1] : n - Arre[index - 1] - 1;

		} else {
			ans = n - Arrs[index - 1] - 1;
			if ((index != E + 1))
				ans += ((targetleft) ? Arrs[index - 1] : n - Arrs[index - 1] - 1);
		}
		return ans;
	}

